// Governance smart contract CBOR encodings
//
// These are Plutus V3 scripts compiled from Aiken source
// See /validators/README.md for compilation instructions

/// Council Governance Validator
///
/// Parameters (applied at deployment):
/// - nft_policy_id: ByteArray (28 bytes) - Policy ID of the governance NFT
/// - initial_utxo_ref: OutputReference - UTxO used for initial deployment
///
/// Rules:
/// - Requires 2/3 of council members to sign updates
/// - NFT must be in inputs and outputs
///
pub const COUNCIL_GOVERNANCE_CBOR: &str = "";

/// Technical Authority Governance Validator
///
/// Parameters (applied at deployment):
/// - nft_policy_id: ByteArray (28 bytes) - Policy ID of the governance NFT
/// - initial_utxo_ref: OutputReference - UTxO used for initial deployment
///
/// Rules:
/// - Requires 2/3 of TA members to sign updates
/// - NFT must be in inputs and outputs
///
#[allow(dead_code)]
pub const TECH_AUTH_GOVERNANCE_CBOR: &str = "";

/// Federated Operators Governance Validator
///
/// Parameters (applied at deployment):
/// - nft_policy_id: ByteArray (28 bytes) - Policy ID of the governance NFT
/// - council_script_hash: ByteArray (28 bytes) - Hash of council governance script
/// - tech_auth_script_hash: ByteArray (28 bytes) - Hash of TA governance script
/// - initial_utxo_ref: OutputReference - UTxO used for initial deployment
///
/// Rules:
/// - Requires 2/3 of BOTH council AND TA members to sign updates
/// - NFT must be in inputs and outputs
/// - Council and TA datums must be provided as reference inputs
///
#[allow(dead_code)]
pub const FEDERATED_OPS_GOVERNANCE_CBOR: &str = "";

